medium', '{"lib/analytics.ts","app/layout.tsx"}', '{"notes":"Lazy-loaded the SDK to avoid blocking initial render."}', '{"Verified events in PostHog dashboard"}', DEFAULT, '2020-02-18T01:05:36.000Z', '2020-06-18T06:02:16.000Z', DEFAULT, DEFAULT, '[]'), ('03001170-4b13-556d-a0ba-beccf9189e29', 1, 'aaaaaaaa-0000-4000-8000-000000000002', 'bbbbbbbb-0000-4000-8000-000000000005', NULL, 'Autemque causa eae sent appeterim, legenturum nec in quidque nullam.', 'Accessibility audit complete', 'Ran axe-core on all pages. Found 12 WCAG AA violations — 8 resolved, 4 deferred to next sprint pending design input.', '{"a11y","quality"}', 'high', '{"components/Button.tsx","components/Modal.tsx","app/page.tsx"}', '{"notes":"Deferred colour-contrast changes until brand refresh is finalised."}', '{"Triaged violations with design","Merged accessibility fixes"}', DEFAULT, '2020-03-19T02:39:08.000Z', '2020-10-10T21:24:11.000Z', DEFAULT, DEFAULT, '[]');
